   113→    if (profileResult.rows.length === 0) {
   114→      throw new Error('User not found');
   115→    }
   116→
   117→    const profile = profileResult.rows[0];
   118→
   119→    // Fetch skills
   120→    const skillsResult = await client.query(
   121→      'SELECT * FROM candidate_skills WHERE user_id = $1',
   122→      [userId]
   123→    );
   124→    profile.skills = skillsResult.rows;
   125→
   126→    // Fetch experience
   127→    const experienceResult = await client.query(
   128→      'SELECT * FROM work_experience WHERE user_id = $1 ORDER BY start_date DESC',
   129→      [userId]
   130→    );
   131→    profile.experience = experienceResult.rows;
   132→
   133→    // Fetch education
   134→    const educationResult = await client.query(
   135→      'SELECT * FROM education WHERE user_id = $1',
   136→      [userId]
   137→    );
   138→    profile.education = educationResult.rows;
   139→
   140→    // Build text for embedding
   141→    const profileText = buildCandidateProfileText(profile);
   142→
   143→    if (!profileText || profileText.trim().length === 0) {
   144→      console.log(`Skipping embedding for user ${userId} - empty profile`);
   145→      return null;
   146→    }
   147→
   148→    // Generate embedding
   149→    const embedding = await generateEmbedding(profileText);
   150→
   151→    // Build summaries
   152→    const skillsSummary = profile.skills.map(s => s.skill_name).join(', ');
   153→    const experienceSummary = profile.experience
   154→      .map(e => `${e.title} at ${e.company}`)
   155→      .slice(0, 3)
   156→      .join('; ');
   157→
   158→    // Upsert embedding
   159→    await client.query(`
   160→      INSERT INTO candidate_embeddings (user_id, embedding, profile_text, skills_summary, experience_summary, last_updated)
   161→      VALUES ($1, $2, $3, $4, $5, NOW())
   162→      ON CONFLICT (user_id)
   163→      DO UPDATE SET
   164→        embedding = $2,
   165→        profile_text = $3,
   166→        skills_summary = $4,
   167→        experience_summary = $5,
   168→        last_updated = NOW()
   169→    `, [userId, toSql(embedding), profileText, skillsSummary, experienceSummary]);
   170→
   171→    console.log(`Updated embedding for candidate ${userId}`);
   172→    return embedding;
   173→  } finally {
   174→    client.release();
   175→  }
   176→}
