   224→/**
   225→ * Calculate cosine similarity between two vectors
   226→ */
   227→function cosineSimilarity(vecA, vecB) {
   228→  if (!vecA || !vecB || vecA.length !== vecB.length) {
   229→    return 0;
   230→  }
   231→
   232→  let dotProduct = 0;
   233→  let normA = 0;
   234→  let normB = 0;
   235→
   236→  for (let i = 0; i < vecA.length; i++) {
   237→    dotProduct += vecA[i] * vecB[i];
   238→    normA += vecA[i] * vecA[i];
   239→    normB += vecB[i] * vecB[i];
   240→  }
   241→
   242→  const magnitude = Math.sqrt(normA) * Math.sqrt(normB);
   243→  return magnitude === 0 ? 0 : dotProduct / magnitude;
   244→}
