   249→async function findMatchingCandidates(jobId, options = {}) {
   250→  const limit = options.limit || 20;
   251→  const minScore = options.minScore || 0.5;
   252→
   253→  const client = await pool.connect();
   254→  try {
   255→    // Ensure job embedding exists
   256→    await updateJobEmbedding(jobId);
   257→
   258→    // Get job details and TrustScore
   259→    const jobResult = await client.query(`
   260→      SELECT j.*, c.name as company_name, ts.total_score as trustscore
   261→      FROM jobs j
   262→      LEFT JOIN companies c ON j.company_id = c.id
   263→      LEFT JOIN trust_scores ts ON c.id = ts.company_id
   264→      WHERE j.id = $1
   265→    `, [jobId]);
   266→
   267→    if (jobResult.rows.length === 0) {
   268→      throw new Error('Job not found');
   269→    }
   270→
   271→    const job = jobResult.rows[0];
   272→    const trustscore = job.trustscore || 500;
   273→
   274→    // Find similar candidates using vector similarity
   275→    const matchResult = await client.query(`
   276→      SELECT
   277→        ce.user_id,
   278→        ce.skills_summary,
   279→        ce.experience_summary,
   280→        os.total_score as omniscore,
   281→        os.score_tier,
   282→        cp.headline,
   283→        cp.location,
   284→        cp.years_experience,
   285→        u.name,
   286→        u.avatar_url,
   287→        1 - (ce.embedding <=> je.embedding) as similarity_score
   288→      FROM candidate_embeddings ce
   289→      INNER JOIN job_embeddings je ON je.job_id = $1
   290→      INNER JOIN users u ON ce.user_id = u.id
   291→      LEFT JOIN omni_scores os ON u.id = os.user_id
   292→      LEFT JOIN candidate_profiles cp ON u.id = cp.user_id
   293→      WHERE u.role = 'candidate'
   294→        AND 1 - (ce.embedding <=> je.embedding) >= $2
   295→      ORDER BY similarity_score DESC
   296→      LIMIT $3
   297→    `, [jobId, minScore, limit]);
   298→
   299→    // Calculate weighted scores with OmniScore and TrustScore
   300→    const matches = matchResult.rows.map(candidate => {
   301→      const omniscore = candidate.omniscore || 300;
   302→      const similarityScore = candidate.similarity_score;
   303→
   304→      // Weighted score formula:
   305→      // Base: similarity (60%)
   306→      // OmniScore boost: normalized 0-1 score * 30%
   307→      // TrustScore boost: normalized 0-1 score * 10%
   308→      const omniNormalized = Math.min(omniscore / 1000, 1); // 0-1 scale
   309→      const trustNormalized = Math.min(trustscore / 1000, 1); // 0-1 scale
   310→
   311→      const weightedScore = (
   312→        (similarityScore * 0.6) +
   313→        (omniNormalized * 0.3) +
   314→        (trustNormalized * 0.1)
   315→      ) * 100; // Scale to 0-100
   316→
   317→      // Determine match level
   318→      let matchLevel = 'poor';
   319→      if (weightedScore >= 85) matchLevel = 'excellent';
   320→      else if (weightedScore >= 70) matchLevel = 'good';
   321→      else if (weightedScore >= 55) matchLevel = 'fair';
   322→
   323→      return {
   324→        candidate_id: candidate.user_id,
   325→        name: candidate.name,
   326→        avatar_url: candidate.avatar_url,
   327→        headline: candidate.headline,
   328→        location: candidate.location,
   329→        years_experience: candidate.years_experience,
   330→        omniscore: omniscore,
   331→        score_tier: candidate.score_tier,
   332→        skills_summary: candidate.skills_summary,
   333→        experience_summary: candidate.experience_summary,
   334→        similarity_score: Math.round(similarityScore * 100) / 100,
   335→        weighted_score: Math.round(weightedScore * 100) / 100,
   336→        match_level: matchLevel,
   337→        explanation: {
   338→          semantic_match: `${Math.round(similarityScore * 100)}% skill and experience alignment`,
   339→          omniscore_boost: `OmniScore ${omniscore} (${candidate.score_tier} tier)`,
   340→          company_trustscore: `Company TrustScore ${trustscore}`
   341→        }
   342→      };
   343→    });
   344→
   345→    // Cache results
   346→    for (const match of matches) {
   347→      await client.query(`
   348→        INSERT INTO match_results (
   349→          candidate_id, job_id, similarity_score, weighted_score,
   350→          omniscore_at_match, trustscore_at_match, match_level,
   351→          match_explanation, calculated_at
   352→        )
   353→        VALUES ($1, $2, $3, $4, $5, $6, $7, $8, NOW())
   354→        ON CONFLICT (candidate_id, job_id)
   355→        DO UPDATE SET
   356→          similarity_score = $3,
   357→          weighted_score = $4,
   358→          omniscore_at_match = $5,
   359→          trustscore_at_match = $6,
   360→          match_level = $7,
   361→          match_explanation = $8,
   362→          calculated_at = NOW()
   363→      `, [
   364→        match.candidate_id,
   365→        jobId,
   366→        match.similarity_score,
   367→        match.weighted_score,
   368→        match.omniscore,
   369→        trustscore,
