      `SELECT a.*, j.title as job_title, j.company
       FROM job_applications a
       LEFT JOIN jobs j ON a.job_id = j.id
       WHERE a.user_id = $1
       ORDER BY a.created_at DESC LIMIT 1`,
      [req.user.id]
    );

