       SET status = 'withdrawn', updated_at = NOW()
       WHERE id = $1 AND company_id = $2 AND status IN ('draft', 'sent', 'viewed')
       RETURNING *`,
      [req.params.id, req.user.company_id]
    );

    if (result.rows.length === 0) {
